import{_ as e,o as i,c as a,a6 as n}from"./chunks/framework.wLlb4ebq.js";const k=JSON.parse('{"title":"Notion 配置","description":"","frontmatter":{},"headers":[],"relativePath":"guide/notion.md","filePath":"guide/notion.md"}'),d={name:"guide/notion.md"};function l(o,t,s,r,h,c){return i(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="notion-配置" tabindex="-1">Notion 配置 <a class="header-anchor" href="#notion-配置" aria-label="Permalink to “Notion 配置”">​</a></h1><p>LD-Notion 需要 Notion 授权后才能读取工作区、创建数据库条目、写入页面块和管理页面元数据。</p><h2 id="授权方式" tabindex="-1">授权方式 <a class="header-anchor" href="#授权方式" aria-label="Permalink to “授权方式”">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>适合场景</th><th>说明</th></tr></thead><tbody><tr><td>Internal Integration Token</td><td>个人使用、最稳定</td><td>手动复制 <code>secret_</code> token 到面板</td></tr><tr><td>Public OAuth</td><td>希望一键授权</td><td>需要配置 Client ID、Client Secret 与 Redirect URI</td></tr></tbody></table><h2 id="创建-integration" tabindex="-1">创建 Integration <a class="header-anchor" href="#创建-integration" aria-label="Permalink to “创建 Integration”">​</a></h2><ol><li>打开 Notion Integrations。</li><li>创建新 Integration，选择目标 Workspace。</li><li>在 Capabilities 中勾选： <ul><li><code>Read content</code></li><li><code>Update content</code></li><li><code>Insert content</code></li></ul></li><li>复制 Internal Integration Token。</li></ol><h2 id="公开-oauth-可选配置" tabindex="-1">公开 OAuth 可选配置 <a class="header-anchor" href="#公开-oauth-可选配置" aria-label="Permalink to “公开 OAuth 可选配置”">​</a></h2><p>如果你使用公开集成授权：</p><ol><li>将 Notion 集成改为 Public。</li><li>添加 Redirect URI，推荐使用 <code>https://www.notion.so/</code>。</li><li>复制 <code>Client ID</code> 和 <code>Client Secret</code>。</li><li>先在 LD-Notion 面板里初始化并解锁本地凭证保险箱。</li><li>在 LD-Notion 面板填写 OAuth 配置。</li><li>点击 <code>一键授权</code>，授权完成后自动把 access token / refresh token 写入本地加密保险箱。</li></ol><div class="warning custom-block"><p class="custom-block-title">注意</p><p>LD-Notion 是纯前端运行。<code>Client Secret</code>、access token、refresh token 和手动 <code>secret_</code> Token 会保存在你的本地加密保险箱中，只有在当前会话解锁后才可直接使用。该模式更适合个人自建公开集成，不适合把共享生产级 secret 放到前端。</p></div><h2 id="数据库属性" tabindex="-1">数据库属性 <a class="header-anchor" href="#数据库属性" aria-label="Permalink to “数据库属性”">​</a></h2><p>推荐数据库包含这些属性：</p><table tabindex="0"><thead><tr><th>属性名</th><th>类型</th><th>用途</th></tr></thead><tbody><tr><td>标题</td><td>Title</td><td>内容标题</td></tr><tr><td>链接</td><td>URL</td><td>原始链接</td></tr><tr><td>分类</td><td>Text</td><td>AI 或规则分类</td></tr><tr><td>标签</td><td>Multi-select</td><td>多标签整理</td></tr><tr><td>作者</td><td>Text</td><td>内容作者</td></tr><tr><td>收藏时间</td><td>Date</td><td>收藏或导入时间</td></tr><tr><td>帖子数</td><td>Number</td><td>Linux.do 回复数量</td></tr><tr><td>浏览数</td><td>Number</td><td>浏览量</td></tr><tr><td>点赞数</td><td>Number</td><td>点赞数</td></tr><tr><td>来源类型</td><td>Select / Text</td><td>Star、Repo、Gist、书签等来源</td></tr><tr><td>书签路径</td><td>Text</td><td>浏览器书签文件夹路径</td></tr></tbody></table><p>实际使用中可以先连接数据库，再用面板中的自动设置能力补齐缺失属性。</p><h2 id="连接-integration" tabindex="-1">连接 Integration <a class="header-anchor" href="#连接-integration" aria-label="Permalink to “连接 Integration”">​</a></h2><ol><li>打开目标数据库或页面。</li><li>点击右上角 <code>...</code>。</li><li>进入 <code>Connections</code>。</li><li>选择刚创建的 Integration。</li></ol><p>这是最容易遗漏的一步。如果未连接 Integration，LD-Notion 即使拿到 token 也无法访问目标数据库或页面。</p><h2 id="选择导出目标" tabindex="-1">选择导出目标 <a class="header-anchor" href="#选择导出目标" aria-label="Permalink to “选择导出目标”">​</a></h2><div class="language-mermaid"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Refresh[刷新工作区列表] --&gt; Choose{选择目标类型}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Choose --&gt; DB[数据库模式\\n创建可筛选条目]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Choose --&gt; Page[页面模式\\n创建子页面或追加块]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  DB --&gt; Import[导入内容]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Page --&gt; Import</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Refresh --&gt; Fallback[加载失败时手动填 32 位 ID]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Fallback --&gt; Import</span></span></code></pre></div><ul><li>数据库模式：适合结构化收藏、排序、筛选、分类和标签。</li><li>页面模式：适合树状笔记或把内容沉淀到指定父页面下。</li></ul><h2 id="验证配置失败时" tabindex="-1">验证配置失败时 <a class="header-anchor" href="#验证配置失败时" aria-label="Permalink to “验证配置失败时”">​</a></h2><p>优先检查：</p><ol><li>Token 是否完整，Internal Integration Token 应以 <code>secret_</code> 开头。</li><li>是否已经把 Integration 连接到数据库或页面。</li><li>是否先刷新工作区列表并选择目标。</li><li>手动输入 ID 时是否只输入 32 位 ID，而不是整段 URL。</li><li>OAuth 模式下 Redirect URI 是否与 Notion 集成配置一致。</li></ol>`,23)])])}const g=e(d,[["render",l]]);export{k as __pageData,g as default};
